# for/else: elegant search without a 'found' flag
def find_prime_factor(n: int) -> int | None:
    """Return the smallest prime factor of n, or None if n is prime."""
    for p in range(2, int(n ** 0.5) + 1):
        if n % p == 0:
            return p   # found — does NOT fall through to else
    else:
        return None    # loop ran without break: n is prime

print(find_prime_factor(49))   # 7
print(find_prime_factor(17))   # None — 17 is prime

# Equivalent with a flag — more verbose, less Pythonic
def find_prime_factor_flag(n: int) -> int | None:
    found = None
    for p in range(2, int(n ** 0.5) + 1):
        if n % p == 0:
            found = p
            break
    return found

# Both produce the same results
for n in [49, 17, 100, 97]:
    a = find_prime_factor(n)
    b = find_prime_factor_flag(n)
    assert a == b
    print(f"{n}: smallest prime factor = {a}")

# WRONG: developer thinks else means "no items found" but means "no break"
def has_invalid(items):
    for item in items:
        if item < 0:
            print("Found negative")
            break
    else:
        print("All valid")  # runs when loop completes WITHOUT break

has_invalid([1, 2, 3])       # "All valid"  — correct
has_invalid([1, -2, 3])      # "Found negative"  — else skipped
has_invalid([])              # "All valid"  — SURPRISE: else runs on empty loop too

# WRONG: using index when only the value is needed
items = ["apple", "banana", "cherry"]
for i in range(len(items)):
    print(items[i])   # verbose, error-prone

# CORRECT: iterate directly
for item in items:
    print(item)

# When you actually need the index, use enumerate
for i, item in enumerate(items):
    print(f"{i}: {item}")

# WRONG: silently ignores all failures
results = []
for item in items:
    try:
        results.append(process(item))
    except:   # catches everything including KeyboardInterrupt!
        pass  # silent failure

# CORRECT: log, count, and limit failures
import logging
results = []
failures = 0
MAX_FAILURES = 3
for item in items:
    try:
        results.append(process(item))
    except Exception as e:
        failures += 1
        logging.warning("Failed processing %r: %s", item, e)
        if failures >= MAX_FAILURES:
            raise RuntimeError(f"Too many failures ({failures}). Aborting.") from e
